module median_filter (
    input [7:0] a,
    input [7:0] b,
    input [7:0] c,
    input [7:0] d,
    input [7:0] e,
    output reg [7:0] median
);

reg [7:0] unsorted [0:4];

integer i, j;

always @(*) begin
    // Load inputs into unsorted array
    unsorted[0] = a;
    unsorted[1] = b;
    unsorted[2] = c;
    unsorted[3] = d;
    unsorted[4] = e;

    // Simple bubble sort to sort the array
    for (i = 0; i < 4; i = i + 1) begin
        for (j = 0; j < 4 - i; j = j + 1) begin
            if (unsorted[j] > unsorted[j + 1]) begin
                // Swap
                {unsorted[j], unsorted[j + 1]} = {unsorted[j + 1], unsorted[j]};
            end
        end
    end

    // Select the median (the middle element in the unsorted array)
    median = unsorted[2];
end

endmodule
